/**
 * Compute the
 * <a href="http://mathworld.wolfram.com/InverseTangent.html" TARGET="_top">
 * inverse tangent</a> of this complex number.
 * Implements the formula:
 * <pre>
 *  <code>
 *   atan(z) = (i/2) log((i + z)/(i - z))
 *  </code>
 * </pre>
 * Returns {@link Complex#NaN} if either real or imaginary part of the
 * input argument is {@code NaN}.
 * Returns {@link Complex#INF} if the input is the imaginary unit I (0.0 + 1.0i)
 * or if the denominator (i - z) becomes zero causing division by zero.
 *
 * @return the inverse tangent of this complex number
 * @since 1.2
 */
public Complex atan() {
    if (isNaN) {
        return NaN;
    }

    // Special case: atan(I) where I = 0.0 + 1.0i
    // This results in division by zero in the formula, so return INF
    if (real == 0.0 && imaginary == 1.0) {
        return INF;
    }

    Complex numerator = this.add(I);
    Complex denominator = I.subtract(this);

    // If denominator is zero, return INF to avoid division by zero
    if (denominator.getReal() == 0.0 && denominator.getImaginary() == 0.0) {
        return INF;
    }

    return numerator.divide(denominator).log()
        .multiply(I.divide(createComplex(2.0, 0.0)));
}

